/**
 * _EditorProps — shared property-panel utilities for GridEditor & LayoutEditor
 *
 * Provides reusable helpers for:
 *   ✦ HTML escaping
 *   ✦ Plugin / component property rendering
 *   ✦ Plugin property event binding
 *   ✦ ColorPicker popup attachment
 */

import razyui from '../index.js';

/** Escape HTML attribute values */
function esc(str) {
    return String(str || '').replace(/&/g, '&amp;').replace(/"/g, '&quot;').replace(/</g, '&lt;');
}

/**
 * Render plugin / component property HTML
 *
 * @param {Array}  properties  — property definitions [{name, label, type, options, default, placeholder}]
 * @param {object} pluginProps — current values
 * @param {string} prefix      — CSS class prefix ('ge' or 'le')
 * @returns {string} HTML
 */
function renderPluginProps(properties, pluginProps, prefix) {
    let html = '';
    properties.forEach(prop => {
        const val = pluginProps[prop.name] ?? prop.default ?? '';
        const escVal = esc(String(val));
        html += `<div class="${prefix}-prop-section">`;
        html += `<label class="${prefix}-prop-label">${esc(prop.label || prop.name)}</label>`;
        if (prop.type === 'select' && prop.options) {
            html += `<select class="${prefix}-prop-input ${prefix}-prop-full" data-plugin-prop="${esc(prop.name)}">`;
            prop.options.forEach(o => {
                const ov = typeof o === 'string' ? o : o.value;
                const ol = typeof o === 'string' ? o : o.label;
                html += `<option value="${esc(ov)}"${String(val) === String(ov) ? ' selected' : ''}>${esc(ol)}</option>`;
            });
            html += '</select>';
        } else if (prop.type === 'boolean') {
            html += `<label class="${prefix}-prop-check-wrap"><input type="checkbox" data-plugin-prop="${esc(prop.name)}"${val ? ' checked' : ''}> ${esc(prop.label || prop.name)}</label>`;
        } else if (prop.type === 'textarea') {
            html += `<textarea class="${prefix}-prop-input ${prefix}-prop-full ${prefix}-prop-textarea" data-plugin-prop="${esc(prop.name)}" rows="3" placeholder="${esc(prop.placeholder || '')}">${escVal}</textarea>`;
        } else if (prop.type === 'number') {
            html += `<input class="${prefix}-prop-input ${prefix}-prop-full" type="number" data-plugin-prop="${esc(prop.name)}" value="${escVal}" placeholder="${esc(prop.placeholder || '')}">`;
        } else {
            html += `<input class="${prefix}-prop-input ${prefix}-prop-full" type="text" data-plugin-prop="${esc(prop.name)}" value="${escVal}" placeholder="${esc(prop.placeholder || '')}">`;
        }
        html += '</div>';
    });
    return html;
}

/**
 * Bind plugin property inputs inside a panel body
 *
 * @param {Element} body       — panel body element
 * @param {object}  element    — data element with pluginProps
 * @param {object}  callbacks
 * @param {function} callbacks.onChange — () => void, called after each change
 * @param {function} callbacks.pushUndo — () => void, called before mutation
 */
function bindPluginProps(body, element, { onChange, pushUndo }) {
    const root = body[0] || body;
    root.querySelectorAll('[data-plugin-prop]').forEach(input => {
        const handler = () => {
            pushUndo();
            if (!element.pluginProps) element.pluginProps = {};
            const prop = input.dataset.pluginProp;
            if (input.type === 'checkbox') {
                element.pluginProps[prop] = input.checked;
            } else if (input.type === 'number') {
                element.pluginProps[prop] = parseFloat(input.value) || 0;
            } else {
                element.pluginProps[prop] = input.value;
            }
            onChange();
        };
        const $input = razyui(input);
        $input.on('change', handler);
        if (input.tagName === 'TEXTAREA') $input.on('input', handler);
    });
}

// ── ColorPicker state ──
let _ColorPicker = null;

/**
 * Attach ColorPicker popups to color swatches
 *
 * @param {Element} body            — panel body with swatches
 * @param {object}  element         — data element (block / el)
 * @param {object}  options
 * @param {string}  options.prefix      — CSS prefix ('ge' or 'le')
 * @param {string}  options.styleAttr   — data attribute basename for input lookup ('block-style' or 'style-prop')
 * @param {Element} options.container   — root container for popup positioning
 * @param {Array}   options.instances   — mutable array of {popup, cp} entries
 * @param {function} options.pushUndo   — () => void
 * @param {function} options.onChange   — (styleProp, value) => void — apply value & re-render
 */
async function attachColorPickers(body, element, options) {
    const { prefix, styleAttr, container, instances, pushUndo, onChange } = options;
    const root = body[0] || body;
    const swatches = root.querySelectorAll(`.${prefix}-prop-color-swatch`);
    if (!swatches.length) return;

    // Lazy-load ColorPicker module once
    if (!_ColorPicker) {
        try {
            const mod = await import('./ColorPicker.js');
            _ColorPicker = mod.default;
            if (mod.css && !document.getElementById('rui-colorpicker-css')) {
                const style = razyui.el('style', { id: 'rui-colorpicker-css', textContent: mod.css });
                document.head.appendChild(style[0]);
            }
        } catch (_) { return; }
    }

    const CP = _ColorPicker;

    swatches.forEach(swatch => {
        razyui(swatch).on('click', (e) => {
            e.stopPropagation();
            closeColorPopups(instances);

            const styleProp = swatch.dataset.colorFor;
            const input = razyui(swatch).parent().find(`[data-${styleAttr}="${styleProp}"]`)[0];
            if (!input) return;

            // Create floating popup container
            const popup = razyui.el('div', { className: `${prefix}-color-popup` });
            const cpHost = razyui.el('div');
            popup.append(cpHost);

            // Position near the swatch
            const rect = swatch.getBoundingClientRect();
            const rootRect = container.getBoundingClientRect();
            popup.css({ position: 'absolute', left: Math.max(0, rect.left - rootRect.left) + 'px', top: (rect.bottom - rootRect.top + 4) + 'px', 'z-index': '9999' });
            container.appendChild(popup[0]);

            const cp = new CP(cpHost[0], {
                mode: 'inline',
                lite: true,
                color: input.value || '#ff0000',
                showAlpha: false,
                showBoard: true,
                persistHistory: false,
                onChange: (color) => {
                    const val = color.transparent ? '' : color.hex;
                    input.value = val;
                    swatch.style.background = val || 'transparent';
                    pushUndo();
                    if (!element.style) element.style = {};
                    element.style[styleProp] = val;
                    onChange(styleProp, val);
                }
            });

            instances.push({ popup, cp });

            // Close on click outside
            const closeHandler = (ev) => {
                if (!popup.contains(ev.target) && ev.target !== swatch) {
                    closeColorPopups(instances);
                    document.removeEventListener('mousedown', closeHandler, true);
                }
            };
            setTimeout(() => document.addEventListener('mousedown', closeHandler, true), 0);
        });
    });
}

/**
 * Close all open ColorPicker popups
 * @param {Array} instances — mutable array of {popup, cp}
 */
function closeColorPopups(instances) {
    instances.forEach(({ popup }) => popup[0].remove());
    instances.length = 0;
}

export { esc, renderPluginProps, bindPluginProps, attachColorPickers, closeColorPopups };
